%[text] # 例6.8（区分的定数関数とDHT）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example06_08"; % mfilename

%imgname = "msipimg01";
%imgname = "msipimg07";
%imgfmt = "tiff";

close all
iFig = 1;
%%
%[text] ## パラメータ設定
J = 3;
M = 2^J;
Delta = 1/M;
R = [0 1]; % サポート領域
%%
%[text] ## $\\varphi(\\cdot)$ のプロット
%phi = @(x) fcn_phin(x,0,K,0,0);
phi = @(x) fcn_chi(x,R);

figure(iFig) %[output:13ac6268]
fplot(@(x) phi(x),R) %[output:13ac6268]
axis([-0.1 1.1 -3 3]) %[output:13ac6268]
ylabel('$\varphi(q)$','Interpreter','latex') %[output:13ac6268]
xlabel('$q$','Interpreter','latex') %[output:13ac6268]

grid on %[output:13ac6268]
iFig = iFig + 1;


%%
%[text] ## $\\varphi\_n(\\cdot)$ の構成
xmin = -1;
%theta0 = 1/(2*K);

phin = cell(M,1);

for n=0:M-1
    %phin{n+1} = @(x) fcn_phin(x,n,K,xmin,theta0);
    phin{n+1} = @(x) fcn_chi((x-n*Delta)/Delta,R)/sqrt(Delta);
end
%%
%[text] ## $\\varphi\_n(\\cdot)$ のプロット
hfig = figure(iFig); %[output:2e4f7b8c]

for n=0:M-1
    subplot(M,1,n+1) %[output:2e4f7b8c]
    fplot(@(x) phin{n+1}(x),R,'k','LineWidth',2)
    axis([-0.1 1.1 -3 3])
    ylabel("$\varphi_"+num2str(n)+"(q)$",'Interpreter','latex')
    ax = gca;
    ax.FontSize = 14;
    if n==M-1
        xlabel('$q$','Interpreter','latex')
    else
        ax.XTickLabel = {};
    end
    grid on
end
figWidth = 400; % 幅（ピクセル）
figHeight = 600; % 高さ（ピクセル）
set(hfig, 'Units', 'pixels', 'Position', [100 100 figWidth figHeight]); %[output:2e4f7b8c]

%exportgraphics(hfig,fullfile(resfolder,"fig06-03a.png"))

iFig = iFig + 1;
%%
%[text] ## $\\psi\_m(\\cdot)$  の構成
f0 = [1 1]/sqrt(2);
f1 = [1 -1]/sqrt(2);

phiab = @(q,a,b) (1./sqrt(a)).*phi((q-b)./a);
psi = @(q) f1(1)*phiab(q,1/2,0)+f1(2)*phiab(q,1/2,1/2);
psiab = @(q,a,b) (1./sqrt(a)).*psi((q-b)./a);

%{
nmax = M/2;

phi0 = @(x,n) fcn_chi(x/Delta-n,R);
phij = cell(J,1);
psij = cell(J,1);

for j=1:J
    if j==1
        phij{j} = @(q,p) f0(1)*phi0(q,2*p)+f0(2)*phi0(q,1+2*p);
        psij{j} = @(q,p) f1(1)*phi0(q,2*p)+f1(2)*phi0(q,1+2*p);
    else
        phij{j} = @(q,p) f0(1)*phij{j-1}(q,2*p)+f0(2)*phij{j-1}(q,1+2*p);
        psij{j} = @(q,p) f1(1)*phij{j-1}(q,2*p)+f1(2)*phij{j-1}(q,1+2*p);
    end
    nmax = nmax/2;
end
%}
%%
%[text] ## $\\psi\_m(\\cdot)$のプロット
hfig = figure(iFig); %[output:554a5261]

% m = 0
subplot(2^J,1,1) %[output:554a5261]
%fplot(@(x) phij{J}(x,0),R,'k','LineWidth',2)
fplot(@(x) phiab(x,1,0),R,'k','LineWidth',2) %[output:554a5261]
axis([-0.1 1.1 -3 3]) %[output:554a5261]
ylabel("$\psi_"+num2str(0)+"(q)$",'Interpreter','latex') %[output:554a5261]
ax = gca;
ax.FontSize = 14; %[output:554a5261]
ax.XTickLabel = {}; %[output:554a5261]
grid on %[output:554a5261]

% m > 0
for m=1:2^J-1
    jm = floor(log2(m));
    am = 2^(-jm);
    bm = am*m-1;
    %jm = J - floor(log2(m)); % 
    %nm = m - 2^floor(log2(m)); 
    subplot(2^J,1,m+1) %[output:554a5261]
    %fplot(@(x) psij{jm}(x,nm),R,'k','LineWidth',2)
    fplot(@(x) psiab(x,am,bm),R,'k','LineWidth',2)
    axis([-0.1 1.1 -3 3])
    ylabel("$\psi_"+num2str(m)+"(q)$",'Interpreter','latex')
    ax = gca;
    ax.FontSize = 14;
    if m==M-1
        xlabel('$q$','Interpreter','latex')
    else
        ax.XTickLabel = {};
    end
    grid on
end
%}

figWidth = 400; % 幅（ピクセル）
figHeight = 600; % 高さ（ピクセル）
set(hfig, 'Units', 'pixels', 'Position', [100 100 figWidth figHeight]); %[output:554a5261]

exportgraphics(hfig,fullfile(resfolder,"fig06-03c.png")) %[output:554a5261]
iFig = iFig + 1;
%%
%[text] ## 補間核の定義
function z = fcn_chi(x,y)
arguments (Input)
    x
    y
end

arguments (Output)
    z
end

z = (x>=y(1)).*(x<y(2));
end
